import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { Link } from 'react-router-dom';
import { CreditCard, ChevronRight, Target, TrendingUp, Sparkles, Activity, Wallet } from 'lucide-react';
import { Button } from '../../components/ui/button';

export default function Dashboard() {
  const { user, profile } = useAuth();
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ proposals: 0, activeHires: 0, winRate: '0%', earnings: 0, escrow: 0 });
  const [contracts, setContracts] = useState<any[]>([]);
  const [isAvailable, setIsAvailable] = useState(true);

  useEffect(() => {
    const fetchDashboardData = async () => {
      if (!user) return;
      setLoading(true);

      const [proposalsRes, contractsRes] = await Promise.all([
        supabase.from('proposals').select('status').eq('freelancer_id', user.uid),
        supabase.from('contracts').select('*, job:jobs(title), milestones(*)').eq('freelancer_id', user.uid)
      ]);

      if (proposalsRes.data) {
        const total = proposalsRes.data.length;
        const hired = proposalsRes.data.filter(p => p.status === 'hired').length;

        let earnings = 0;
        let escrow = 0;
        if (contractsRes.data) {
          contractsRes.data.forEach(c => {
            escrow += Number(c.total_budget) || 0;
            c.milestones?.forEach((m: any) => {
              if (m.status === 'completed') earnings += (Number(m.amount.toString().replace(/[^0-9.-]+/g,"")) || 0);
            });
          });
          setContracts(contractsRes.data);
        }

        setStats({
          proposals: total,
          activeHires: hired,
          winRate: total > 0 ? Math.round((hired / total) * 100) + '%' : '0%',
          earnings,
          escrow
        });
      }
      setLoading(false);
    };

    fetchDashboardData();
  }, [user]);

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in duration-500 px-4">

      {/* Top Banner & Availability */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white p-8 rounded-3xl border border-slate-200 shadow-sm relative overflow-hidden">
        <div className="absolute right-0 top-0 w-64 h-64 bg-blue-600/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/4"></div>
        <div className="relative z-10">
          <h1 className="text-3xl font-black text-black tracking-tight flex items-center gap-3">
            Hello, {profile?.full_name?.split(' ')[0] || 'Professional'} <span className="text-2xl">≡ƒæï</span>
          </h1>
          <p className="text-slate-500 font-medium mt-1">Here is exactly what's happening with your WorkLink pipeline today.</p>
        </div>

        <div className="relative z-10 flex items-center bg-slate-50 p-2 pl-6 rounded-2xl border border-slate-200 shadow-inner">
          <span className="text-sm font-bold text-slate-600 mr-4">Looking for Work</span>
          <button 
            onClick={() => setIsAvailable(!isAvailable)}
            className={`w-16 h-8 rounded-full p-1 transition-colors duration-300 ease-in-out ${isAvailable ? 'bg-blue-600' : 'bg-slate-300'}`}
          >
            <div className={`w-6 h-6 bg-white rounded-full shadow-md transform transition-transform duration-300 ${isAvailable ? 'translate-x-8' : 'translate-x-0'}`}></div>
          </button>
        </div>
      </div>

      {/* The Core Stat Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { title: "Total Earnings", value: `Γé╣${stats.earnings.toLocaleString()}`, icon: Wallet, color: "blue" },
          { title: "In-Escrow", value: `Γé╣${stats.escrow.toLocaleString()}`, icon: CreditCard, color: "slate" },
          { title: "Active Hires", value: stats.activeHires, icon: Activity, color: "green" },
          { title: "Proposal Win Rate", value: stats.winRate, icon: TrendingUp, color: "yellow" }
        ].map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow group flex flex-col justify-between">
            <div className="flex items-start justify-between mb-4">
              <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${
                stat.color === 'blue' ? 'bg-blue-50 text-blue-600' : 
                stat.color === 'green' ? 'bg-emerald-50 text-emerald-600' : 
                stat.color === 'yellow' ? 'bg-amber-50 text-amber-600' : 
                'bg-slate-50 text-slate-600'
              } group-hover:scale-110 transition-transform duration-300`}>
                <stat.icon className="w-6 h-6" />
              </div>
            </div>
            <div>
              <p className="text-3xl font-black text-black mb-1">{stat.value}</p>
              <p className="text-sm font-bold text-slate-500 uppercase tracking-wide">{stat.title}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid lg:grid-cols-3 gap-8">

        {/* Project Pipeline */}
        <div className="lg:col-span-2 bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full">
          <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <div>
              <h2 className="text-xl font-black text-black">Project Pipeline</h2>
              <p className="text-sm font-medium text-slate-500 mt-1">Active tasks and milestone tracking.</p>
            </div>
            <Link to="/proposals" className="text-blue-600 hover:text-blue-700 font-bold text-sm bg-blue-50 px-4 py-2 rounded-lg transition-colors">
              View All
            </Link>
          </div>

          <div className="p-8 flex-1">
            {contracts.length > 0 ? (
              <div className="space-y-6">
                {contracts.slice(0, 3).map((contract, i) => {
                  const completedCount = contract.milestones?.filter((m: any) => m.status === 'completed').length || 0;
                  const totalCount = contract.milestones?.length || 1;
                  const progress = Math.round((completedCount / totalCount) * 100);

                  return (
                    <Link key={i} to={`/workroom/${contract.id}`} className="group block">
                      <div className="flex justify-between items-center mb-3 text-left">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center font-black">
                            {contract.job?.title?.substring(0, 2).toUpperCase() || 'WR'}
                          </div>
                          <div>
                            <h4 className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors">{contract.job?.title || 'Active Contract'}</h4>
                            <p className="text-xs font-bold uppercase tracking-widest text-slate-400 mt-1">{contract.status || 'Active'}</p>
                          </div>
                        </div>
                        <span className="font-bold text-black border border-slate-200 px-3 py-1 rounded-full text-sm">
                          {progress}%
                        </span>
                      </div>
                      <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-blue-600 rounded-full transition-all duration-1000 ease-out"
                          style={{ width: `${progress}%` }}
                        ></div>
                      </div>
                    </Link>
                  );
                })}
              </div>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-center p-8 bg-slate-50 rounded-2xl border border-dashed border-slate-200 min-h-[300px]">
                <Target className="w-12 h-12 text-slate-400 mb-4" />
                <h3 className="font-black text-lg text-slate-800">Your Pipeline is Empty</h3>
                <p className="text-sm text-slate-500 font-medium max-w-sm mt-2 mb-6">Browse the job feed and submit compelling proposals to start filling your project queue.</p>
                <Link to="/jobs">
                  <Button className="bg-blue-600 hover:bg-blue-700 text-white font-bold h-14 px-8 rounded-xl shadow-lg shadow-blue-600/20 text-lg">
                    Find Opportunities
                  </Button>
                </Link>
              </div>
            )}
          </div>
        </div>

        {/* AI Co-Pilot Widget */}
        <div className="bg-slate-900 rounded-3xl border border-slate-800 shadow-xl overflow-hidden relative text-white flex flex-col h-full min-h-[400px]">
          <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/20 rounded-full blur-3xl translate-x-1/2 -translate-y-1/2"></div>

          <div className="p-8 relative z-10 flex-1 flex flex-col">
            <div className="w-12 h-12 bg-blue-600/20 text-blue-500 rounded-xl flex items-center justify-center mb-6">
              <Sparkles className="w-6 h-6" />
            </div>
            <h2 className="text-xl font-black mb-2">AI Co-Pilot Insights</h2>
            <p className="text-slate-400 text-sm font-medium mb-8 leading-relaxed">
              Based on global trends connecting <span className="text-white font-bold">{profile?.skills?.[0] || 'your core skills'}</span>, we suggest these targeted actions:
            </p>

            <div className="space-y-4 flex-1">
              <div className="bg-slate-800/50 hover:bg-slate-800 p-4 rounded-xl border border-slate-700/50 cursor-pointer transition-colors group">
                <h4 className="font-bold text-sm text-white group-hover:text-blue-400 flex items-center justify-between">
                  Update Portfolio <ChevronRight className="w-4 h-4 opacity-0 group-hover:opacity-100 -translate-x-2 group-hover:translate-x-0 transition-all" />
                </h4>
                <p className="text-xs text-slate-400 mt-1 leading-relaxed">Clients are prioritizing explicit Case Studies detailing exactly how you execute API models. Add one now.</p>
              </div>
              <div className="bg-slate-800/50 hover:bg-slate-800 p-4 rounded-xl border border-slate-700/50 cursor-pointer transition-colors group">
                <h4 className="font-bold text-sm text-white group-hover:text-blue-400 flex items-center justify-between">
                  Draft Proposals <ChevronRight className="w-4 h-4 opacity-0 group-hover:opacity-100 -translate-x-2 group-hover:translate-x-0 transition-all" />
                </h4>
                <p className="text-xs text-slate-400 mt-1 leading-relaxed">You have a strong match rate with 3 new active high-budget postings.</p>
              </div>
            </div>

            <Button variant="outline" className="w-full mt-6 border-slate-700 text-slate-300 hover:text-white hover:bg-slate-800 h-12 font-bold">
              Ask Assistant
            </Button>
          </div>
        </div>

      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import { ArrowRight, LayoutGrid, List, Briefcase, TrendingUp, Users, DollarSign, Clock } from 'lucide-react';
import { Button } from '../../components/ui/button';
import SpendingChart from '../../components/SpendingChart';


// Removed static STATS and MOCK_JOBS

export default function Dashboard() {
  const { user, profile } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [jobs, setJobs] = useState<any[]>([]);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [stats, setStats] = useState<any[]>([
    { label: 'Active Jobs', value: '0', icon: Briefcase, color: 'text-blue-600', bg: 'bg-blue-50', border: 'border-blue-100' },
    { label: 'Total Applicants', value: '0', icon: Users, color: 'text-emerald-600', bg: 'bg-emerald-50', border: 'border-emerald-100' },
    { label: 'Escrow Balance', value: 'Γé╣0', icon: DollarSign, color: 'text-amber-600', bg: 'bg-amber-50', border: 'border-amber-100' },
    { label: 'Hires', value: '0', icon: Clock, color: 'text-purple-600', bg: 'bg-purple-50', border: 'border-purple-100' },
  ]);

  useEffect(() => {
    const fetchDashboardData = async () => {
      if (!user) return;
      setLoading(true);

      const [jobsRes, statsRes, proposalsRes] = await Promise.all([
        supabase.from('jobs').select('*').eq('recruiter_id', user.uid).order('created_at', { ascending: false }),
        supabase.from('contracts').select('total_budget').eq('recruiter_id', user.uid),
        supabase.from('proposals').select('id', { count: 'exact' }).in('job_id', (await supabase.from('jobs').select('id').eq('recruiter_id', user.uid)).data?.map(j => j.id) || [])
      ]);

      if (jobsRes.data) {
        setJobs(jobsRes.data);
      }

      setStats([
        { label: 'Active Jobs', value: String(jobsRes.data?.filter(j => j.status === 'open').length || 0), icon: Briefcase, color: 'text-blue-600', bg: 'bg-blue-50', border: 'border-blue-100' },
        { label: 'Total Applicants', value: String(proposalsRes.count || 0), icon: Users, color: 'text-emerald-600', bg: 'bg-emerald-50', border: 'border-emerald-100' },
        { label: 'Escrow Balance', value: `Γé╣${(statsRes.data?.reduce((acc, curr) => acc + (Number(curr.total_budget) || 0), 0) || 0).toLocaleString()}`, icon: DollarSign, color: 'text-amber-600', bg: 'bg-amber-50', border: 'border-amber-100' },
        { label: 'Hires', value: String(statsRes.data?.length || 0), icon: Clock, color: 'text-purple-600', bg: 'bg-purple-50', border: 'border-purple-100' },
      ]);

      setLoading(false);
    };

    fetchDashboardData();
  }, [user]);

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-in fade-in duration-500 px-4 py-6">
      {/* Top Banner */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white p-8 rounded-3xl border border-slate-200 shadow-sm relative overflow-hidden">
        <div className="absolute right-0 top-0 w-96 h-96 bg-blue-600/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/4"></div>
        <div className="relative z-10">
          <h1 className="text-4xl md:text-5xl font-black text-black tracking-tight">
            Good day, {profile?.full_name?.split(' ')[0] || 'Recruiter'} ≡ƒæï
          </h1>
          <p className="text-slate-500 font-medium text-lg mt-2">
            Your hiring command center. <span className="text-blue-600 font-bold">{jobs.filter(j => j.status === 'open').length} active jobs</span> live right now.
          </p>
        </div>
        <div className="relative z-10">
          <Button onClick={() => navigate('/post-job')} className="bg-blue-600 hover:bg-blue-700 text-white font-bold h-14 px-8 rounded-xl shadow-xl shadow-blue-600/20 text-lg flex items-center gap-2">
            Post a job <ArrowRight className="w-5 h-5" />
          </Button>
        </div>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {stats.map((s, i) => (
          <div key={i} className={`bg-white border rounded-2xl px-5 py-4 flex items-center gap-4 ${s.border} ${loading ? 'animate-pulse' : ''}`}>
            <div className={`w-12 h-12 ${s.bg} ${s.color} rounded-xl flex items-center justify-center shrink-0`}>
              <s.icon className="w-6 h-6" />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-wide">{s.label}</p>
              <p className="text-2xl font-black text-slate-900">{loading ? '...' : s.value}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Spending Area Chart */}
      <SpendingChart />



      <div className="grid lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2">
          {/* Jobs Grid */}
          <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
              <div>
                <h2 className="text-xl font-black text-black">Your Postings</h2>
                <p className="text-sm font-medium text-slate-500 mt-0.5">
                  {jobs.length} postings ┬╖ {jobs.filter(j => j.status === 'open').length} live
                </p>
              </div>
              <div className="flex bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setViewMode('grid')} className={`w-10 h-10 flex items-center justify-center rounded-lg transition-colors ${viewMode === 'grid' ? 'bg-white shadow border border-slate-200 text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}>
                  <LayoutGrid className="w-5 h-5" />
                </button>
                <button onClick={() => setViewMode('list')} className={`w-10 h-10 flex items-center justify-center rounded-lg transition-colors ${viewMode === 'list' ? 'bg-white shadow border border-slate-200 text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}>
                  <List className="w-5 h-5" />
                </button>
              </div>
            </div>
            <div className="p-6">
              <div className={viewMode === 'grid' ? 'grid md:grid-cols-2 gap-4' : 'space-y-3'}>
                {loading ? (
                  [1, 2, 3, 4].map(i => (
                    <div key={i} className="h-32 bg-slate-50 border border-slate-100 rounded-2xl animate-pulse"></div>
                  ))
                ) : jobs.length === 0 ? (
                  <div className="text-center py-12">
                     <p className="font-bold text-slate-400 italic">No job posts yet. Start by posting your first job!</p>
                  </div>
                ) : (
                  jobs.map((job, i) => (
                    <div
                      key={job.id || i}
                      onClick={() => navigate('/kanban')}
                      className={`group bg-white border border-slate-200 rounded-2xl p-5 hover:border-blue-400 hover:shadow-md transition-all cursor-pointer ${viewMode === 'list' ? 'flex items-center justify-between' : ''}`}
                    >
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-2 flex-wrap">
                          <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold uppercase tracking-widest ${job.status === 'open' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-slate-100 text-slate-500 border border-slate-200'}`}>
                            {job.status === 'open' ? '≡ƒƒó Live' : 'ΓÜ¬ Draft'}
                          </span>
                          {job.category && (
                            <span className="text-xs font-bold text-blue-600 bg-blue-50 border border-blue-100 px-2 py-0.5 rounded-full">{job.category}</span>
                          )}
                        </div>
                        <h4 className="font-bold text-base text-slate-900 group-hover:text-blue-600 transition-colors line-clamp-1">{job.title}</h4>
                        <p className="text-xs font-medium text-slate-500 mt-1 line-clamp-2">{job.description}</p>
                        <p className="text-xs font-black text-blue-600 mt-2">View details ΓåÆ</p>
                      </div>
                      {viewMode === 'list' && (
                        <div className="shrink-0 ml-4 flex items-center gap-2">
                          <span className="bg-slate-50 text-slate-700 border border-slate-200 font-bold px-3 py-1.5 rounded-xl text-xs hover:bg-slate-100 transition-colors">View</span>
                        </div>
                      )}
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Sidebar */}
        <div className="space-y-6">
          {/* Spend Overview */}
          <div className="bg-white border border-slate-200 rounded-3xl p-6">
            <h3 className="font-black text-slate-900 mb-4 flex items-center gap-2">
              <TrendingUp className="w-5 h-5 text-blue-600" /> Spend Overview
            </h3>
            <div className="space-y-4">
              {[
                { label: 'This Month', value: 'Γé╣2,40,000', bar: 60 },
                { label: 'Last Month', value: 'Γé╣1,85,000', bar: 46 },
                { label: 'Q1 Total', value: 'Γé╣7,20,000', bar: 80 },
              ].map((item, i) => (
                <div key={i}>
                  <div className="flex justify-between text-sm mb-1.5">
                    <span className="font-bold text-slate-600">{item.label}</span>
                    <span className="font-black text-slate-900">{item.value}</span>
                  </div>
                  <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                    <div className="h-full bg-blue-600 rounded-full transition-all" style={{ width: `${item.bar}%` }}></div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Top Consultants */}
          <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 text-white">
            <h3 className="font-black text-lg mb-4">Top Consultants</h3>
            <div className="space-y-3">
              {[
                { name: 'Elena Rodriguez', role: 'Full Stack Architect', rate: 'Γé╣15k/hr' },
                { name: 'David Chen', role: 'Senior UI/UX', rate: 'Γé╣8k/hr' },
                { name: 'Marcus Johnson', role: 'Cloud Systems', rate: 'Γé╣12k/hr' },
                { name: 'Priya Patel', role: 'ML Engineer', rate: 'Γé╣9k/hr' },
              ].map((expert, i) => (
                <div
                  key={i}
                  onClick={() => navigate(`/profile/${i + 1}`)}
                  className="bg-slate-800 hover:bg-slate-700 cursor-pointer transition-colors rounded-2xl p-3 border border-slate-700/50 flex gap-3 items-center group"
                >
                  <div className="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center text-white font-black text-sm shrink-0">
                    {expert.name.split(' ').map(n => n[0]).join('')}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-bold text-white text-sm truncate group-hover:text-blue-400">{expert.name}</p>
                    <p className="text-xs text-slate-400">{expert.role} ┬╖ <span className="text-emerald-400">{expert.rate}</span></p>
                  </div>
                </div>
              ))}
            </div>
            <Button onClick={() => navigate('/talent')} className="w-full mt-5 bg-white hover:bg-slate-100 text-black font-bold h-11 rounded-xl text-sm">
              Browse All Talent
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

